class Solution:
    def isValid(self, word: str) -> bool:
        vowels = set("aeiouAEIOU")
        consonants = set("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ")
        allowed_chars = set("0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ")

        if len(word) < 3:
            return False

        has_vowel = False
        has_consonant = False

        for char in word:
            if char not in allowed_chars:
                return False
            if char in vowels:
                has_vowel = True
            elif char in consonants:
                has_consonant = True

        return has_vowel and has_consonant
